var COURSE_DE_PL = [{day: 1, title: `Erste Grüße und Höflichkeit`, title_native: `Pierwsze powitania i uprzejmość`, focus: `Du kommst in Warschau an und brauchst sofort höfliche Standardwörter. Heute lernst du Begrüßungen, Verabschiedungen und einfache Höflichkeitsformen für jeden Kontakt.`, vocab: [{pl: `cześć`, de: `hallo/tschüss`, ipa: `tscheschtsch`},{pl: `dzień dobry`, de: `guten Tag`, ipa: `dschjen dob-ri`},{pl: `dobry wieczór`, de: `guten Abend`, ipa: `dob-ri wjetschur`},{pl: `do widzenia`, de: `auf Wiedersehen`, ipa: `do wi-dse-nja`},{pl: `proszę`, de: `bitte`, ipa: `pro-sche`},{pl: `dziękuję`, de: `danke`, ipa: `dschjen-ku-je`},{pl: `przepraszam`, de: `entschuldigung`, ipa: `psche-pra-scham`},{pl: `tak`, de: `ja`, ipa: `tak`},{pl: `nie`, de: `nein`, ipa: `nje`},{pl: `dobrze`, de: `gut`, ipa: `dob-sche`}], phrases: [{pl: `Dzień dobry.`, de: `Guten Tag.`, ipa: `dschjen dob-ri`},{pl: `Cześć, jak się masz?`, de: `Hallo, wie geht es dir?`, ipa: `tscheschtsch jak schje masch`},{pl: `Dziękuję bardzo.`, de: `Vielen Dank.`, ipa: `dschjen-ku-je bar-dso`},{pl: `Przepraszam, nie rozumiem.`, de: `Entschuldigung, ich verstehe nicht.`, ipa: `psche-pra-scham nje ro-su-mjem`},{pl: `Do widzenia.`, de: `Auf Wiedersehen.`, ipa: `do wi-dse-nja`},{pl: `Tak, dobrze.`, de: `Ja, gut.`, ipa: `tak dob-sche`}], grammar: `Polnisch unterscheidet oft zwischen formeller und informeller Sprache. In Hotels, Restaurants oder Geschäften beginnst du sicher mit „Dzień dobry“ statt „Cześć“. „Proszę“ ist besonders nützlich, weil es je nach Situation „bitte“, „hier bitte“ oder „gern geschehen“ bedeuten kann.`, practice: [`Begrüße eine Person an der Hotelrezeption auf Polnisch.`,`Sage höflich „Danke“ und „Auf Wiedersehen“.`,`Übe den Unterschied zwischen „tak“ und „nie“ mit fünf schnellen Antworten.`,`Sage: „Entschuldigung, ich verstehe nicht.“`,`Stelle dir vor, du kaufst Wasser in Warschau und verwendest „proszę“ und „dziękuję“.`]},{day: 2, title: `Namen, Herkunft und einfache Vorstellung`, title_native: `Imiona, pochodzenie i proste przedstawianie się`, focus: `In Krakau triffst du andere Reisende und möchtest dich kurz vorstellen. Heute lernst du, Namen, Herkunft und Grundinformationen zu sagen.`, vocab: [{pl: `imię`, de: `Vorname`, ipa: `i-mje`},{pl: `nazwisko`, de: `Nachname`, ipa: `nas-wis-ko`},{pl: `jestem`, de: `ich bin`, ipa: `jes-tem`},{pl: `mam`, de: `ich habe`, ipa: `mam`},{pl: `Niemcy`, de: `Deutschland`, ipa: `njem-tsi`},{pl: `Austria`, de: `Österreich`, ipa: `aus-trja`},{pl: `Szwajcaria`, de: `Schweiz`, ipa: `schwai-tsa-rja`},{pl: `turysta`, de: `Tourist`, ipa: `tu-ris-ta`},{pl: `turystka`, de: `Touristin`, ipa: `tu-ris-tka`},{pl: `miło`, de: `angenehm/schön`, ipa: `mi-wo`}], phrases: [{pl: `Mam na imię Anna.`, de: `Ich heiße Anna.`, ipa: `mam na i-mje an-na`},{pl: `Jestem z Niemiec.`, de: `Ich bin aus Deutschland.`, ipa: `jes-tem s njem-jets`},{pl: `Jestem turystą.`, de: `Ich bin Tourist.`, ipa: `jes-tem tu-ris-tom`},{pl: `Jestem turystką.`, de: `Ich bin Touristin.`, ipa: `jes-tem tu-ris-tkom`},{pl: `Miło mi.`, de: `Freut mich.`, ipa: `mi-wo mi`},{pl: `Jak masz na imię?`, de: `Wie heißt du?`, ipa: `jak masch na i-mje`}], grammar: `„Jestem“ bedeutet „ich bin“ und ist eines der wichtigsten Verben für den Start. Nach „z“ sagt man im Alltag häufig die Herkunft: „z Niemiec“, „z Austrii“, „ze Szwajcarii“. Bei „turysta“ und „turystka“ achtest du auf das Geschlecht der sprechenden Person.`, practice: [`Stelle dich mit deinem Namen vor.`,`Sage, dass du aus Deutschland, Österreich oder der Schweiz kommst.`,`Frage eine andere Person nach ihrem Namen.`,`Antworte mit „Miło mi“.`,`Baue einen Mini-Dialog mit drei Zeilen: Begrüßung, Name, Herkunft.`]},{day: 3, title: `Zahlen von 0 bis 20`, title_native: `Liczby od 0 do 20`, focus: `In Łódź brauchst du Zahlen beim Bezahlen, für Zimmernummern und Uhrzeiten. Heute lernst du die wichtigsten kleinen Zahlen.`, vocab: [{pl: `zero`, de: `null`, ipa: `se-ro`},{pl: `jeden`, de: `eins`, ipa: `je-den`},{pl: `dwa`, de: `zwei`, ipa: `dwa`},{pl: `trzy`, de: `drei`, ipa: `tschi`},{pl: `cztery`, de: `vier`, ipa: `tsch-te-ri`},{pl: `pięć`, de: `fünf`, ipa: `pjen-tsch`},{pl: `sześć`, de: `sechs`, ipa: `scheschtsch`},{pl: `siedem`, de: `sieben`, ipa: `sche-dem`},{pl: `osiem`, de: `acht`, ipa: `o-schem`},{pl: `dziewięć`, de: `neun`, ipa: `dsche-wjen-tsch`}], phrases: [{pl: `Mam jeden bilet.`, de: `Ich habe ein Ticket.`, ipa: `mam je-den bi-let`},{pl: `Dwa bilety, proszę.`, de: `Zwei Tickets, bitte.`, ipa: `dwa bi-le-ti pro-sche`},{pl: `Pokój numer trzy.`, de: `Zimmer Nummer drei.`, ipa: `po-kuj nu-mer tschi`},{pl: `To kosztuje pięć złotych.`, de: `Das kostet fünf Złoty.`, ipa: `to kosch-tu-je pjen-tsch swo-tich`},{pl: `Mam sześć dni.`, de: `Ich habe sechs Tage.`, ipa: `mam scheschtsch dni`},{pl: `Numer telefonu?`, de: `Telefonnummer?`, ipa: `nu-mer te-le-fo-nu`}], grammar: `Polnische Zahlen verändern manchmal die Form des folgenden Nomens. Für Reisende reicht am Anfang eine feste Kombination wie „jeden bilet“ oder „dwa bilety“. Die Währung heißt „złoty“, aber nach vielen Zahlen hörst du „złote“ oder „złotych“.`, practice: [`Zähle auf Polnisch von 0 bis 10.`,`Bestelle zwei Tickets.`,`Sage eine Zimmernummer zwischen 1 und 9.`,`Frage nach einer Telefonnummer.`,`Übe drei Preise: 5, 8 und 10 Złoty.`]},{day: 4, title: `Mehr Zahlen, Preise und Alter`, title_native: `Więcej liczb, ceny i wiek`, focus: `In Breslau siehst du Preise auf Speisekarten und in Museen. Heute erweiterst du Zahlen bis 100 und fragst nach Kosten.`, vocab: [{pl: `dziesięć`, de: `zehn`, ipa: `dsche-schjen-tsch`},{pl: `jedenaście`, de: `elf`, ipa: `je-de-na-sch-tsche`},{pl: `dwanaście`, de: `zwölf`, ipa: `dwa-na-sch-tsche`},{pl: `dwadzieścia`, de: `zwanzig`, ipa: `dwa-dsje-sch-tscha`},{pl: `trzydzieści`, de: `dreißig`, ipa: `tschi-dsje-sch-tschi`},{pl: `czterdzieści`, de: `vierzig`, ipa: `tsch-ter-dsje-sch-tschi`},{pl: `pięćdziesiąt`, de: `fünfzig`, ipa: `pjenj-dsje-schont`},{pl: `sto`, de: `hundert`, ipa: `sto`},{pl: `cena`, de: `Preis`, ipa: `tse-na`},{pl: `złoty`, de: `Złoty`, ipa: `swo-ti`}], phrases: [{pl: `Ile to kosztuje?`, de: `Wie viel kostet das?`, ipa: `i-le to kosch-tu-je`},{pl: `To kosztuje dwadzieścia złotych.`, de: `Das kostet zwanzig Złoty.`, ipa: `to kosch-tu-je dwa-dsje-sch-tscha swo-tich`},{pl: `Mam trzydzieści lat.`, de: `Ich bin dreißig Jahre alt.`, ipa: `mam tschi-dsje-sch-tschi lat`},{pl: `Poproszę rachunek.`, de: `Die Rechnung bitte.`, ipa: `po-pro-sche ra-chu-nek`},{pl: `Czy mogę zapłacić kartą?`, de: `Kann ich mit Karte bezahlen?`, ipa: `tschi mo-ge sa-pwa-tschitsch kar-tom`},{pl: `To za drogo.`, de: `Das ist zu teuer.`, ipa: `to sa dro-go`}], grammar: `„Ile?“ bedeutet „wie viel?“ oder „wie viele?“ und ist beim Einkaufen extrem wichtig. Für das Alter sagt man im Polnischen wörtlich „Ich habe dreißig Jahre“: „Mam trzydzieści lat“. Beim Bezahlen ist „kartą“ die praktische Form für „mit Karte“.`, practice: [`Frage nach dem Preis eines Kaffees.`,`Sage drei Preise zwischen 20 und 100.`,`Sage dein Alter mit „Mam ... lat“.`,`Bitte um die Rechnung.`,`Frage, ob du mit Karte zahlen kannst.`]},{day: 5, title: `Bitte, danke und Überlebenssätze`, title_native: `Proszę, dziękuję i zdania ratunkowe`, focus: `In Danzig möchtest du höflich bleiben, auch wenn du nicht alles verstehst. Heute lernst du Sätze, die in fast jeder Reisesituation helfen.`, vocab: [{pl: `pomoc`, de: `Hilfe`, ipa: `po-mots`},{pl: `język`, de: `Sprache`, ipa: `jen-sik`},{pl: `polski`, de: `polnisch`, ipa: `pol-ski`},{pl: `niemiecki`, de: `deutsch`, ipa: `njem-jets-ki`},{pl: `angielski`, de: `englisch`, ipa: `an-gjel-ski`},{pl: `wolno`, de: `langsam`, ipa: `wol-no`},{pl: `jeszcze raz`, de: `noch einmal`, ipa: `jesch-tsche ras`},{pl: `problem`, de: `Problem`, ipa: `pro-blem`},{pl: `chwila`, de: `Moment`, ipa: `chwi-la`},{pl: `oczywiście`, de: `natürlich`, ipa: `o-tschi-wisch-tsche`}], phrases: [{pl: `Czy mówi pan po niemiecku?`, de: `Sprechen Sie Deutsch?`, ipa: `tschi mu-wi pan po njem-jets-ku`},{pl: `Czy mówi pani po angielsku?`, de: `Sprechen Sie Englisch?`, ipa: `tschi mu-wi pa-ni po an-gjel-sku`},{pl: `Proszę mówić wolno.`, de: `Bitte sprechen Sie langsam.`, ipa: `pro-sche mu-witsch wol-no`},{pl: `Jeszcze raz, proszę.`, de: `Noch einmal, bitte.`, ipa: `jesch-tsche ras pro-sche`},{pl: `Potrzebuję pomocy.`, de: `Ich brauche Hilfe.`, ipa: `po-tsche-bu-je po-mo-tsi`},{pl: `Nie ma problemu.`, de: `Kein Problem.`, ipa: `nje ma pro-ble-mu`}], grammar: `Im Polnischen gibt es höfliche Formen für „Sie“: „pan“ für einen Mann, „pani“ für eine Frau. In Service-Situationen klingt „Czy mówi pan/pani...?“ sehr respektvoll. „Po polsku“, „po niemiecku“ und „po angielsku“ bedeuten „auf Polnisch“, „auf Deutsch“ und „auf Englisch“.`, practice: [`Frage eine Frau höflich, ob sie Englisch spricht.`,`Bitte jemanden, langsam zu sprechen.`,`Sage, dass du Hilfe brauchst.`,`Bitte um Wiederholung.`,`Reagiere auf ein Missverständnis mit „Nie ma problemu“.`]},{day: 6, title: `Orientierung in der Stadt`, title_native: `Orientacja w mieście`, focus: `In Krakau suchst du den Marktplatz, die Altstadt und dein Hotel. Heute lernst du Richtungen und Orte in der Stadt.`, vocab: [{pl: `miasto`, de: `Stadt`, ipa: `mjas-to`},{pl: `ulica`, de: `Straße`, ipa: `u-li-tsa`},{pl: `rynek`, de: `Marktplatz`, ipa: `ri-nek`},{pl: `hotel`, de: `Hotel`, ipa: `ho-tel`},{pl: `dworzec`, de: `Bahnhof`, ipa: `dwo-schets`},{pl: `centrum`, de: `Zentrum`, ipa: `tsen-trum`},{pl: `prawo`, de: `rechts`, ipa: `pra-wo`},{pl: `lewo`, de: `links`, ipa: `le-wo`},{pl: `prosto`, de: `geradeaus`, ipa: `pros-to`},{pl: `blisko`, de: `nah`, ipa: `blis-ko`}], phrases: [{pl: `Gdzie jest rynek?`, de: `Wo ist der Marktplatz?`, ipa: `gdschje jest ri-nek`},{pl: `Gdzie jest hotel?`, de: `Wo ist das Hotel?`, ipa: `gdschje jest ho-tel`},{pl: `Proszę iść prosto.`, de: `Gehen Sie bitte geradeaus.`, ipa: `pro-sche ischtsch pros-to`},{pl: `W prawo czy w lewo?`, de: `Nach rechts oder nach links?`, ipa: `w pra-wo tschi w le-wo`},{pl: `To jest blisko.`, de: `Das ist nah.`, ipa: `to jest blis-ko`},{pl: `To jest daleko.`, de: `Das ist weit.`, ipa: `to jest da-le-ko`}], grammar: `„Gdzie jest...?“ ist die einfache Frage „Wo ist...?“. Richtungen stehen oft mit „w“: „w prawo“ und „w lewo“. Für Reisende ist es wichtiger, diese Ausdrücke zu erkennen, als perfekte Fälle zu bilden.`, practice: [`Frage nach dem Bahnhof.`,`Frage nach dem Hotel.`,`Gib jemandem eine einfache Richtung: geradeaus und rechts.`,`Entscheide, ob ein Ort nah oder weit ist.`,`Spiele eine Szene: Du suchst den Rynek in Krakau.`]},{day: 7, title: `Transport: Bahnhof, Bus und Taxi`, title_native: `Transport: dworzec, autobus i taksówka`, focus: `In Poznań bewegst du dich mit Zug, Straßenbahn und Taxi. Heute lernst du die wichtigsten Wörter für öffentlichen Verkehr.`, vocab: [{pl: `pociąg`, de: `Zug`, ipa: `po-tschong`},{pl: `autobus`, de: `Bus`, ipa: `au-to-bus`},{pl: `tramwaj`, de: `Straßenbahn`, ipa: `tram-wai`},{pl: `taksówka`, de: `Taxi`, ipa: `tak-suf-ka`},{pl: `bilet`, de: `Ticket`, ipa: `bi-let`},{pl: `peron`, de: `Bahnsteig`, ipa: `pe-ron`},{pl: `przystanek`, de: `Haltestelle`, ipa: `pschi-sta-nek`},{pl: `lotnisko`, de: `Flughafen`, ipa: `lot-nis-ko`},{pl: `odjazd`, de: `Abfahrt`, ipa: `od-jasd`},{pl: `przyjazd`, de: `Ankunft`, ipa: `pschi-jasd`}], phrases: [{pl: `Poproszę bilet do Krakowa.`, de: `Ein Ticket nach Krakau bitte.`, ipa: `po-pro-sche bi-let do kra-ko-wa`},{pl: `Gdzie jest peron drugi?`, de: `Wo ist Bahnsteig zwei?`, ipa: `gdschje jest pe-ron dru-gi`},{pl: `Kiedy odjeżdża pociąg?`, de: `Wann fährt der Zug ab?`, ipa: `kje-di od-je-schdscha po-tschong`},{pl: `Czy to jest przystanek autobusowy?`, de: `Ist das die Bushaltestelle?`, ipa: `tschi to jest pschi-sta-nek au-to-bu-so-wi`},{pl: `Proszę na lotnisko.`, de: `Zum Flughafen bitte.`, ipa: `pro-sche na lot-nis-ko`},{pl: `Ile kosztuje taksówka?`, de: `Wie viel kostet ein Taxi?`, ipa: `i-le kosch-tu-je tak-suf-ka`}], grammar: `Nach „do“ steht oft ein Ziel: „do Krakowa“, „do Warszawy“, „do hotelu“. Für Verkehrsmittel reicht oft ein kurzer Satz mit „proszę“: „Proszę na lotnisko“. Die Frage „Kiedy?“ bedeutet „wann?“ und ist für Abfahrtszeiten zentral.`, practice: [`Kaufe ein Ticket nach Krakau.`,`Frage nach Bahnsteig zwei.`,`Frage, wann der Zug abfährt.`,`Sage dem Taxifahrer: „Zum Flughafen bitte.“`,`Erkenne die Wörter für Zug, Bus und Straßenbahn.`]},{day: 8, title: `Im Hotel einchecken`, title_native: `Zameldowanie w hotelu`, focus: `In Warschau kommst du spät im Hotel an. Heute lernst du Wörter und Sätze für Rezeption, Reservierung und Zimmer.`, vocab: [{pl: `rezerwacja`, de: `Reservierung`, ipa: `re-ser-wa-tsja`},{pl: `pokój`, de: `Zimmer`, ipa: `po-kuj`},{pl: `klucz`, de: `Schlüssel`, ipa: `klutsch`},{pl: `paszport`, de: `Reisepass`, ipa: `pasch-port`},{pl: `noc`, de: `Nacht`, ipa: `nots`},{pl: `śniadanie`, de: `Frühstück`, ipa: `schnja-da-nje`},{pl: `winda`, de: `Aufzug`, ipa: `win-da`},{pl: `piętro`, de: `Stockwerk`, ipa: `pjen-tro`},{pl: `łazienka`, de: `Badezimmer`, ipa: `wa-schjen-ka`},{pl: `łóżko`, de: `Bett`, ipa: `wusch-ko`}], phrases: [{pl: `Mam rezerwację.`, de: `Ich habe eine Reservierung.`, ipa: `mam re-ser-wa-tsje`},{pl: `Na nazwisko Müller.`, de: `Auf den Namen Müller.`, ipa: `na nas-wis-ko müller`},{pl: `Czy śniadanie jest w cenie?`, de: `Ist Frühstück im Preis inbegriffen?`, ipa: `tschi schnja-da-nje jest w tse-nje`},{pl: `Gdzie jest winda?`, de: `Wo ist der Aufzug?`, ipa: `gdschje jest win-da`},{pl: `Potrzebuję klucza.`, de: `Ich brauche den Schlüssel.`, ipa: `po-tsche-bu-je klu-tscha`},{pl: `Pokój jest bardzo dobry.`, de: `Das Zimmer ist sehr gut.`, ipa: `po-kuj jest bar-dso dob-ri`}], grammar: `„Mam rezerwację“ ist ein sehr nützlicher Satz beim Check-in. „Na nazwisko...“ heißt wörtlich „auf Nachname...“ und wird an Rezeptionen oft verwendet. Bei Fragen kannst du mit „Czy...?“ beginnen, ähnlich wie ein allgemeines Fragewort.`, practice: [`Sage, dass du eine Reservierung hast.`,`Gib einen Nachnamen an.`,`Frage, ob Frühstück im Preis enthalten ist.`,`Frage nach dem Aufzug.`,`Beschreibe dein Zimmer mit „dobry“ oder „bardzo dobry“.`]},{day: 9, title: `Essen und Trinken im Café`, title_native: `Jedzenie i picie w kawiarni`, focus: `In einer Krakauer Kawiarnia bestellst du Kaffee und ein kleines Frühstück. Heute lernst du Bestellungen in Cafés und einfache Speisen.`, vocab: [{pl: `kawa`, de: `Kaffee`, ipa: `ka-wa`},{pl: `herbata`, de: `Tee`, ipa: `her-ba-ta`},{pl: `woda`, de: `Wasser`, ipa: `wo-da`},{pl: `mleko`, de: `Milch`, ipa: `mle-ko`},{pl: `cukier`, de: `Zucker`, ipa: `tsu-kjer`},{pl: `kanapka`, de: `Sandwich`, ipa: `ka-nap-ka`},{pl: `ciasto`, de: `Kuchen`, ipa: `tschjas-to`},{pl: `rogal`, de: `Croissant/Hörnchen`, ipa: `ro-gal`},{pl: `stolik`, de: `Tisch`, ipa: `sto-lik`},{pl: `menu`, de: `Speisekarte`, ipa: `me-nü`}], phrases: [{pl: `Poproszę kawę.`, de: `Einen Kaffee bitte.`, ipa: `po-pro-sche ka-we`},{pl: `Poproszę herbatę z cytryną.`, de: `Einen Tee mit Zitrone bitte.`, ipa: `po-pro-sche her-ba-te s tsi-tri-nom`},{pl: `Czy macie mleko?`, de: `Haben Sie Milch?`, ipa: `tschi ma-tsche mle-ko`},{pl: `Bez cukru, proszę.`, de: `Ohne Zucker bitte.`, ipa: `bes tsu-kru pro-sche`},{pl: `Czy jest wolny stolik?`, de: `Ist ein Tisch frei?`, ipa: `tschi jest wol-ni sto-lik`},{pl: `Poproszę menu.`, de: `Die Karte bitte.`, ipa: `po-pro-sche me-nü`}], grammar: `„Poproszę“ ist beim Bestellen die sicherste Form und bedeutet ungefähr „Ich hätte gern“. Mit „z“ sagst du „mit“, wie in „z cytryną“. „Bez“ bedeutet „ohne“ und ist sehr praktisch für Zucker, Milch oder Allergien.`, practice: [`Bestelle Kaffee ohne Zucker.`,`Bestelle Tee mit Zitrone.`,`Frage nach einem freien Tisch.`,`Bitte um die Speisekarte.`,`Erstelle eine Café-Bestellung mit Getränk und Kuchen.`]},{day: 10, title: `Im Restaurant bestellen`, title_native: `Zamawianie w restauracji`, focus: `In Danzig gehst du in ein Restaurant und möchtest lokale Gerichte probieren. Heute lernst du Bestellwörter, Speisen und höfliche Fragen.`, vocab: [{pl: `restauracja`, de: `Restaurant`, ipa: `res-tau-ra-tsja`},{pl: `zupa`, de: `Suppe`, ipa: `su-pa`},{pl: `pierogi`, de: `Pierogi`, ipa: `pje-ro-gi`},{pl: `mięso`, de: `Fleisch`, ipa: `mjen-so`},{pl: `ryba`, de: `Fisch`, ipa: `ri-ba`},{pl: `sałatka`, de: `Salat`, ipa: `sa-wat-ka`},{pl: `chleb`, de: `Brot`, ipa: `chlep`},{pl: `sól`, de: `Salz`, ipa: `sul`},{pl: `pieprz`, de: `Pfeffer`, ipa: `pjep-sch`},{pl: `rachunek`, de: `Rechnung`, ipa: `ra-chu-nek`}], phrases: [{pl: `Co pan poleca?`, de: `Was empfehlen Sie?`, ipa: `tso pan po-le-tsa`},{pl: `Co pani poleca?`, de: `Was empfehlen Sie?`, ipa: `tso pa-ni po-le-tsa`},{pl: `Poproszę pierogi.`, de: `Pierogi bitte.`, ipa: `po-pro-sche pje-ro-gi`},{pl: `Czy to jest z mięsem?`, de: `Ist das mit Fleisch?`, ipa: `tschi to jest s mjen-sem`},{pl: `Poproszę wodę gazowaną.`, de: `Sprudelwasser bitte.`, ipa: `po-pro-sche wo-de ga-so-wa-nom`},{pl: `Rachunek, proszę.`, de: `Die Rechnung bitte.`, ipa: `ra-chu-nek pro-sche`}], grammar: `„Co pan/pani poleca?“ ist eine elegante und praktische Frage im Restaurant. „Czy to jest z...?“ hilft dir, Zutaten zu prüfen. Polnische Gerichte wie „pierogi“ werden oft im Plural verwendet, auch wenn du einfach „Pierogi“ bestellst.`, practice: [`Frage den Kellner nach einer Empfehlung.`,`Bestelle Pierogi und Wasser.`,`Frage, ob ein Gericht Fleisch enthält.`,`Bitte um Salz und Pfeffer.`,`Bitte am Ende um die Rechnung.`]},{day: 11, title: `Ernährung, Allergien und Vorlieben`, title_native: `Dieta, alergie i preferencje`, focus: `In Breslau willst du sicher essen und Zutaten verstehen. Heute lernst du Sätze für Allergien, vegetarische Optionen und persönliche Vorlieben.`, vocab: [{pl: `alergia`, de: `Allergie`, ipa: `a-ler-gja`},{pl: `orzechy`, de: `Nüsse`, ipa: `o-sche-chi`},{pl: `mleko`, de: `Milch`, ipa: `mle-ko`},{pl: `gluten`, de: `Gluten`, ipa: `glu-ten`},{pl: `wegetariański`, de: `vegetarisch`, ipa: `we-ge-ta-rjan-ski`},{pl: `wegański`, de: `vegan`, ipa: `we-gan-ski`},{pl: `bez`, de: `ohne`, ipa: `bes`},{pl: `lubię`, de: `ich mag`, ipa: `lu-bje`},{pl: `nie lubię`, de: `ich mag nicht`, ipa: `nje lu-bje`},{pl: `ostry`, de: `scharf`, ipa: `os-tri`}], phrases: [{pl: `Mam alergię na orzechy.`, de: `Ich habe eine Nussallergie.`, ipa: `mam a-ler-gje na o-sche-chi`},{pl: `Czy to jest bez glutenu?`, de: `Ist das glutenfrei?`, ipa: `tschi to jest bes glu-te-nu`},{pl: `Czy macie dania wegetariańskie?`, de: `Haben Sie vegetarische Gerichte?`, ipa: `tschi ma-tsche da-nja we-ge-ta-rjan-skje`},{pl: `Nie jem mięsa.`, de: `Ich esse kein Fleisch.`, ipa: `nje jem mjen-sa`},{pl: `Lubię ostre jedzenie.`, de: `Ich mag scharfes Essen.`, ipa: `lu-bje os-tre je-dse-nje`},{pl: `To jest za ostre.`, de: `Das ist zu scharf.`, ipa: `to jest sa os-tre`}], grammar: `„Mam alergię na...“ ist der wichtigste Satz bei Allergien. „Nie jem...“ bedeutet „ich esse nicht...“ und ist direkter als lange Erklärungen. „Bez“ plus Zutat ist oft auf Speisekarten sichtbar, zum Beispiel „bez glutenu“.`, practice: [`Sage, dass du kein Fleisch isst.`,`Frage nach vegetarischen Gerichten.`,`Sage, dass du eine Allergie gegen Nüsse hast.`,`Frage, ob ein Gericht glutenfrei ist.`,`Beschreibe, ob du scharfes Essen magst.`]},{day: 12, title: `Einkaufen im kleinen Laden`, title_native: `Zakupy w małym sklepie`, focus: `In Lublin kaufst du Snacks, Wasser und kleine Dinge im Laden. Heute lernst du Einkaufswörter und einfache Fragen an der Kasse.`, vocab: [{pl: `sklep`, de: `Laden`, ipa: `sklep`},{pl: `kasa`, de: `Kasse`, ipa: `ka-sa`},{pl: `torba`, de: `Tasche`, ipa: `tor-ba`},{pl: `paragon`, de: `Kassenbon`, ipa: `pa-ra-gon`},{pl: `woda`, de: `Wasser`, ipa: `wo-da`},{pl: `jabłko`, de: `Apfel`, ipa: `jab-ko`},{pl: `ser`, de: `Käse`, ipa: `ser`},{pl: `chleb`, de: `Brot`, ipa: `chlep`},{pl: `gazeta`, de: `Zeitung`, ipa: `ga-se-ta`},{pl: `reszta`, de: `Wechselgeld`, ipa: `resch-ta`}], phrases: [{pl: `Poproszę wodę.`, de: `Wasser bitte.`, ipa: `po-pro-sche wo-de`},{pl: `Czy mogę dostać torbę?`, de: `Kann ich eine Tasche bekommen?`, ipa: `tschi mo-ge dos-tatsch tor-be`},{pl: `Czy płacę tutaj?`, de: `Bezahle ich hier?`, ipa: `tschi pwa-tse tu-tai`},{pl: `Kartą czy gotówką?`, de: `Mit Karte oder bar?`, ipa: `kar-tom tschi go-tuf-kom`},{pl: `Poproszę paragon.`, de: `Den Kassenbon bitte.`, ipa: `po-pro-sche pa-ra-gon`},{pl: `Dziękuję, do widzenia.`, de: `Danke, auf Wiedersehen.`, ipa: `dschjen-ku-je do wi-dse-nja`}], grammar: `Beim Einkaufen hörst du oft „Kartą czy gotówką?“ — „mit Karte oder bar?“. „Poproszę“ funktioniert auch für Produkte: „Poproszę chleb“. Wenn du eine Tasche brauchst, ist „Czy mogę dostać torbę?“ höflich und klar.`, practice: [`Kaufe Wasser und Brot.`,`Frage nach einer Tasche.`,`Antworte auf „Kartą czy gotówką?“.`,`Bitte um den Kassenbon.`,`Beende den Einkauf höflich.`]},{day: 13, title: `Kleidung, Größen und Farben`, title_native: `Ubrania, rozmiary i kolory`, focus: `In einem Einkaufszentrum in Katowice suchst du ein T-Shirt oder eine Jacke. Heute lernst du Größen, Farben und Umkleidefragen.`, vocab: [{pl: `ubranie`, de: `Kleidung`, ipa: `u-bra-nje`},{pl: `koszulka`, de: `T-Shirt`, ipa: `ko-schul-ka`},{pl: `kurtka`, de: `Jacke`, ipa: `kurt-ka`},{pl: `spodnie`, de: `Hose`, ipa: `spod-nje`},{pl: `buty`, de: `Schuhe`, ipa: `bu-ti`},{pl: `rozmiar`, de: `Größe`, ipa: `ros-mjar`},{pl: `mały`, de: `klein`, ipa: `ma-wi`},{pl: `duży`, de: `groß`, ipa: `du-schi`},{pl: `czarny`, de: `schwarz`, ipa: `tschar-ni`},{pl: `biały`, de: `weiß`, ipa: `bja-wi`}], phrases: [{pl: `Czy macie większy rozmiar?`, de: `Haben Sie eine größere Größe?`, ipa: `tschi ma-tsche wjenk-schi ros-mjar`},{pl: `Czy macie mniejszy rozmiar?`, de: `Haben Sie eine kleinere Größe?`, ipa: `tschi ma-tsche mnjey-schi ros-mjar`},{pl: `Gdzie jest przymierzalnia?`, de: `Wo ist die Umkleidekabine?`, ipa: `gdschje jest pschi-mje-schal-nja`},{pl: `Poproszę czarną koszulkę.`, de: `Ein schwarzes T-Shirt bitte.`, ipa: `po-pro-sche tschar-nom ko-schul-ke`},{pl: `Ile to kosztuje?`, de: `Wie viel kostet das?`, ipa: `i-le to kosch-tu-je`},{pl: `To mi pasuje.`, de: `Das passt mir.`, ipa: `to mi pa-su-je`}], grammar: `Farben passen sich im Polnischen oft dem Nomen an, aber als Reisender darfst du zuerst feste Kombinationen lernen. „Czarna koszulka“ bedeutet „schwarzes T-Shirt“, weil „koszulka“ weiblich ist. „To mi pasuje“ ist sehr praktisch für Kleidung und bedeutet „das passt mir“.`, practice: [`Frage nach einer größeren Größe.`,`Frage nach der Umkleidekabine.`,`Bitte um ein schwarzes T-Shirt.`,`Sage, dass etwas dir passt.`,`Frage nach dem Preis einer Jacke.`]},{day: 14, title: `Zeit, Tage und Termine`, title_native: `Czas, dni i terminy`, focus: `In Toruń planst du Museum, Restaurant und Zugfahrt. Heute lernst du Uhrzeiten, Tage und einfache Zeitfragen.`, vocab: [{pl: `czas`, de: `Zeit`, ipa: `tschas`},{pl: `godzina`, de: `Stunde/Uhrzeit`, ipa: `go-dschi-na`},{pl: `dzisiaj`, de: `heute`, ipa: `dschi-schaj`},{pl: `jutro`, de: `morgen`, ipa: `ju-tro`},{pl: `wczoraj`, de: `gestern`, ipa: `ftscho-rai`},{pl: `rano`, de: `morgens`, ipa: `ra-no`},{pl: `wieczorem`, de: `abends`, ipa: `wje-tscho-rem`},{pl: `poniedziałek`, de: `Montag`, ipa: `po-nje-dsja-wek`},{pl: `sobota`, de: `Samstag`, ipa: `so-bo-ta`},{pl: `niedziela`, de: `Sonntag`, ipa: `nje-dsje-la`}], phrases: [{pl: `Która godzina?`, de: `Wie spät ist es?`, ipa: `ktu-ra go-dschi-na`},{pl: `O której godzinie?`, de: `Um wie viel Uhr?`, ipa: `o ktu-rej go-dschi-nje`},{pl: `Dzisiaj mam czas.`, de: `Heute habe ich Zeit.`, ipa: `dschi-schaj mam tschas`},{pl: `Jutro nie mogę.`, de: `Morgen kann ich nicht.`, ipa: `ju-tro nje mo-ge`},{pl: `Czy muzeum jest otwarte?`, de: `Ist das Museum geöffnet?`, ipa: `tschi mu-se-um jest ot-far-te`},{pl: `Do zobaczenia jutro.`, de: `Bis morgen.`, ipa: `do so-ba-tsche-nja ju-tro`}], grammar: `„Która godzina?“ fragt nach der Uhrzeit. „O której godzinie?“ fragt nach einem Termin oder Beginn. Viele Öffnungszeiten verwenden „otwarte“ für geöffnet und „zamknięte“ für geschlossen.`, practice: [`Frage nach der Uhrzeit.`,`Frage, um wie viel Uhr ein Museum öffnet.`,`Sage, dass du heute Zeit hast.`,`Sage, dass du morgen nicht kannst.`,`Vereinbare ein Wiedersehen für morgen.`]},{day: 15, title: `Tickets, Museen und Sehenswürdigkeiten`, title_native: `Bilety, muzea i zabytki`, focus: `In Krakau besuchst du Wawel und Museen. Heute lernst du Eintrittskarten, Öffnungszeiten und touristische Fragen.`, vocab: [{pl: `muzeum`, de: `Museum`, ipa: `mu-se-um`},{pl: `zamek`, de: `Schloss/Burg`, ipa: `sa-mek`},{pl: `kościół`, de: `Kirche`, ipa: `ko-sch-tschuw`},{pl: `bilet ulgowy`, de: `ermäßigtes Ticket`, ipa: `bi-let ul-go-wi`},{pl: `bilet normalny`, de: `normales Ticket`, ipa: `bi-let nor-mal-ni`},{pl: `wejście`, de: `Eingang`, ipa: `wej-sch-tsche`},{pl: `wyjście`, de: `Ausgang`, ipa: `wi-sch-tsche`},{pl: `otwarte`, de: `geöffnet`, ipa: `ot-far-te`},{pl: `zamknięte`, de: `geschlossen`, ipa: `sam-knjen-te`},{pl: `zwiedzanie`, de: `Besichtigung`, ipa: `swje-dsa-nje`}], phrases: [{pl: `Poproszę jeden bilet normalny.`, de: `Ein normales Ticket bitte.`, ipa: `po-pro-sche je-den bi-let nor-mal-ni`},{pl: `Czy są bilety ulgowe?`, de: `Gibt es ermäßigte Tickets?`, ipa: `tschi som bi-le-ti ul-go-ve`},{pl: `Gdzie jest wejście?`, de: `Wo ist der Eingang?`, ipa: `gdschje jest wej-sch-tsche`},{pl: `Gdzie jest wyjście?`, de: `Wo ist der Ausgang?`, ipa: `gdschje jest wi-sch-tsche`},{pl: `O której zamykacie?`, de: `Um wie viel Uhr schließen Sie?`, ipa: `o ktu-rej sa-mi-ka-tsche`},{pl: `Czy można robić zdjęcia?`, de: `Darf man Fotos machen?`, ipa: `tschi mosch-na ro-bitsch sdschjen-tscha`}], grammar: `„Można“ bedeutet „man kann/darf“ und ist in öffentlichen Orten sehr nützlich. „Czy można robić zdjęcia?“ ist höflich und vermeidet direkte Befehle. Für Tickets kannst du einfach mit „Poproszę jeden...” beginnen.`, practice: [`Kaufe ein normales Ticket.`,`Frage nach ermäßigten Tickets.`,`Frage nach Eingang und Ausgang.`,`Frage, ob man Fotos machen darf.`,`Frage, wann das Museum schließt.`]},{day: 16, title: `Wegbeschreibung verstehen`, title_native: `Rozumienie wskazówek drogi`, focus: `In Warschau fragst du nach dem Weg zur U-Bahn und bekommst eine Antwort. Heute lernst du typische Richtungsangaben genauer zu verstehen.`, vocab: [{pl: `metro`, de: `U-Bahn`, ipa: `me-tro`},{pl: `most`, de: `Brücke`, ipa: `most`},{pl: `plac`, de: `Platz`, ipa: `plats`},{pl: `skrzyżowanie`, de: `Kreuzung`, ipa: `skschi-scho-wa-nje`},{pl: `światła`, de: `Ampel`, ipa: `schfjat-wa`},{pl: `naprzeciwko`, de: `gegenüber`, ipa: `na-psche-tschiw-ko`},{pl: `obok`, de: `neben`, ipa: `o-bok`},{pl: `za`, de: `hinter`, ipa: `sa`},{pl: `przed`, de: `vor`, ipa: `pschet`},{pl: `między`, de: `zwischen`, ipa: `mjen-dsi`}], phrases: [{pl: `Proszę skręcić w lewo.`, de: `Biegen Sie bitte links ab.`, ipa: `pro-sche skren-tschitsch w le-wo`},{pl: `Proszę skręcić w prawo.`, de: `Biegen Sie bitte rechts ab.`, ipa: `pro-sche skren-tschitsch w pra-wo`},{pl: `Metro jest obok hotelu.`, de: `Die U-Bahn ist neben dem Hotel.`, ipa: `me-tro jest o-bok ho-te-lu`},{pl: `Apteka jest naprzeciwko.`, de: `Die Apotheke ist gegenüber.`, ipa: `ap-te-ka jest na-psche-tschiw-ko`},{pl: `Proszę iść do świateł.`, de: `Gehen Sie bitte bis zur Ampel.`, ipa: `pro-sche ischtsch do schfja-tew`},{pl: `To jest za mostem.`, de: `Das ist hinter der Brücke.`, ipa: `to jest sa mos-tem`}], grammar: `Wegbeschreibungen nutzen oft Ortswörter wie „obok“, „za“ und „naprzeciwko“. Du musst nicht jeden Fall perfekt bilden, aber du solltest die Kernwörter erkennen. „Skręcić“ bedeutet „abbiegen“ und kommt oft in höflichen Anweisungen vor.`, practice: [`Sage: „Biegen Sie rechts ab.“`,`Frage, ob die U-Bahn neben dem Hotel ist.`,`Beschreibe eine Apotheke gegenüber.`,`Bitte um den Weg bis zur Ampel.`,`Zeichne eine kleine Karte und benutze drei polnische Ortswörter.`]},{day: 17, title: `Gesundheit und Apotheke`, title_native: `Zdrowie i apteka`, focus: `In Zakopane brauchst du Kopfschmerztabletten oder etwas gegen Erkältung. Heute lernst du Sätze für Apotheke und einfache Beschwerden.`, vocab: [{pl: `apteka`, de: `Apotheke`, ipa: `ap-te-ka`},{pl: `lekarz`, de: `Arzt`, ipa: `le-kasch`},{pl: `ból`, de: `Schmerz`, ipa: `bul`},{pl: `głowa`, de: `Kopf`, ipa: `gwo-wa`},{pl: `brzuch`, de: `Bauch`, ipa: `bschuch`},{pl: `gardło`, de: `Hals`, ipa: `gar-dwo`},{pl: `gorączka`, de: `Fieber`, ipa: `go-rontsch-ka`},{pl: `tabletki`, de: `Tabletten`, ipa: `ta-blet-ki`},{pl: `recepta`, de: `Rezept`, ipa: `re-tsep-ta`},{pl: `pomoc`, de: `Hilfe`, ipa: `po-mots`}], phrases: [{pl: `Boli mnie głowa.`, de: `Mein Kopf tut weh.`, ipa: `bo-li mnje gwo-wa`},{pl: `Boli mnie brzuch.`, de: `Mein Bauch tut weh.`, ipa: `bo-li mnje bschuch`},{pl: `Mam gorączkę.`, de: `Ich habe Fieber.`, ipa: `mam go-rontsch-ke`},{pl: `Potrzebuję tabletek.`, de: `Ich brauche Tabletten.`, ipa: `po-tsche-bu-je ta-ble-tek`},{pl: `Czy potrzebuję recepty?`, de: `Brauche ich ein Rezept?`, ipa: `tschi po-tsche-bu-je re-tsep-ti`},{pl: `Gdzie jest najbliższa apteka?`, de: `Wo ist die nächste Apotheke?`, ipa: `gdschje jest naj-blisch-scha ap-te-ka`}], grammar: `Für Schmerzen sagt man oft „Boli mnie...“ plus Körperteil. Wörtlich heißt es etwa „es schmerzt mich der Kopf“. „Potrzebuję“ bedeutet „ich brauche“ und ist in der Apotheke sehr nützlich.`, practice: [`Sage, dass dein Kopf weh tut.`,`Sage, dass du Fieber hast.`,`Frage nach der nächsten Apotheke.`,`Frage, ob du ein Rezept brauchst.`,`Bitte um Tabletten.`]},{day: 18, title: `Notfälle und Sicherheit`, title_native: `Nagłe sytuacje i bezpieczeństwo`, focus: `In einer fremden Stadt brauchst du klare Sätze für Notfälle. Heute lernst du Hilfe rufen, Probleme erklären und wichtige Orte nennen.`, vocab: [{pl: `policja`, de: `Polizei`, ipa: `po-li-tsja`},{pl: `szpital`, de: `Krankenhaus`, ipa: `schpi-tal`},{pl: `pogotowie`, de: `Rettungsdienst`, ipa: `po-go-to-wje`},{pl: `wypadek`, de: `Unfall`, ipa: `wi-pa-dek`},{pl: `zgubiłem`, de: `ich habe verloren`, ipa: `sgu-bi-wem`},{pl: `zgubiłam`, de: `ich habe verloren`, ipa: `sgu-bi-wam`},{pl: `portfel`, de: `Geldbörse`, ipa: `port-fel`},{pl: `telefon`, de: `Telefon`, ipa: `te-le-fon`},{pl: `dokumenty`, de: `Dokumente`, ipa: `do-ku-men-ti`},{pl: `niebezpiecznie`, de: `gefährlich`, ipa: `nje-bes-pjetsch-nje`}], phrases: [{pl: `Potrzebuję pomocy.`, de: `Ich brauche Hilfe.`, ipa: `po-tsche-bu-je po-mo-tsi`},{pl: `Proszę zadzwonić na policję.`, de: `Bitte rufen Sie die Polizei.`, ipa: `pro-sche sad-swo-nitsch na po-li-tsje`},{pl: `Zgubiłem portfel.`, de: `Ich habe meine Geldbörse verloren.`, ipa: `sgu-bi-wem port-fel`},{pl: `Zgubiłam telefon.`, de: `Ich habe mein Telefon verloren.`, ipa: `sgu-bi-wam te-le-fon`},{pl: `Gdzie jest szpital?`, de: `Wo ist das Krankenhaus?`, ipa: `gdschje jest schpi-tal`},{pl: `To jest pilne.`, de: `Das ist dringend.`, ipa: `to jest pil-ne`}], grammar: `Bei „ich habe verloren“ gibt es eine männliche und weibliche Sprecherform: „zgubiłem“ und „zgubiłam“. In Notfällen sind kurze Sätze besser als perfekte Grammatik. „To jest pilne“ macht klar, dass es dringend ist.`, practice: [`Sage, dass du Hilfe brauchst.`,`Bitte jemanden, die Polizei zu rufen.`,`Sage, dass du dein Telefon verloren hast.`,`Frage nach dem Krankenhaus.`,`Übe einen Notfall-Dialog mit drei kurzen Sätzen.`]},{day: 19, title: `Wetter und Kleidung unterwegs`, title_native: `Pogoda i ubrania w podróży`, focus: `In Gdynia wechselst du zwischen Sonne, Wind und Regen. Heute lernst du Wetterwörter und passende Reiseentscheidungen.`, vocab: [{pl: `pogoda`, de: `Wetter`, ipa: `po-go-da`},{pl: `słońce`, de: `Sonne`, ipa: `swojn-tse`},{pl: `deszcz`, de: `Regen`, ipa: `deschtsch`},{pl: `wiatr`, de: `Wind`, ipa: `wjatr`},{pl: `zimno`, de: `kalt`, ipa: `schim-no`},{pl: `ciepło`, de: `warm`, ipa: `tschjep-wo`},{pl: `gorąco`, de: `heiß`, ipa: `go-ront-so`},{pl: `parasolka`, de: `Regenschirm`, ipa: `pa-ra-sol-ka`},{pl: `płaszcz`, de: `Mantel`, ipa: `pwaschtsch`},{pl: `buty`, de: `Schuhe`, ipa: `bu-ti`}], phrases: [{pl: `Jaka jest pogoda?`, de: `Wie ist das Wetter?`, ipa: `ja-ka jest po-go-da`},{pl: `Pada deszcz.`, de: `Es regnet.`, ipa: `pa-da deschtsch`},{pl: `Jest zimno.`, de: `Es ist kalt.`, ipa: `jest schim-no`},{pl: `Jest ciepło.`, de: `Es ist warm.`, ipa: `jest tschjep-wo`},{pl: `Potrzebuję parasolki.`, de: `Ich brauche einen Regenschirm.`, ipa: `po-tsche-bu-je pa-ra-sol-ki`},{pl: `Dzisiaj jest ładna pogoda.`, de: `Heute ist schönes Wetter.`, ipa: `dschi-schaj jest wad-na po-go-da`}], grammar: `Für Wetter benutzt Polnisch oft einfache Konstruktionen mit „jest“: „jest zimno“, „jest ciepło“. „Pada deszcz“ heißt wörtlich „Regen fällt“. Das Adjektiv „ładna“ bedeutet hier „schön“ und passt zu „pogoda“.`, practice: [`Frage nach dem Wetter.`,`Sage, dass es regnet.`,`Sage, dass es kalt ist.`,`Bitte um einen Regenschirm.`,`Beschreibe das Wetter heute in einem Satz.`]},{day: 20, title: `Telefon, WLAN und digitale Hilfe`, title_native: `Telefon, Wi-Fi i pomoc cyfrowa`, focus: `In einem Hotel oder Café in Warschau brauchst du WLAN und Akkuladung. Heute lernst du digitale Alltagswörter für Reisende.`, vocab: [{pl: `telefon`, de: `Telefon`, ipa: `te-le-fon`},{pl: `internet`, de: `Internet`, ipa: `in-ter-net`},{pl: `Wi-Fi`, de: `WLAN`, ipa: `wai-fai`},{pl: `hasło`, de: `Passwort`, ipa: `has-wo`},{pl: `ładowarka`, de: `Ladegerät`, ipa: `wa-do-var-ka`},{pl: `bateria`, de: `Akku/Batterie`, ipa: `ba-te-rja`},{pl: `gniazdko`, de: `Steckdose`, ipa: `gnjast-ko`},{pl: `aplikacja`, de: `App`, ipa: `a-pli-ka-tsja`},{pl: `mapa`, de: `Karte`, ipa: `ma-pa`},{pl: `adres`, de: `Adresse`, ipa: `a-dres`}], phrases: [{pl: `Jakie jest hasło do Wi-Fi?`, de: `Wie lautet das WLAN-Passwort?`, ipa: `ja-kje jest has-wo do wai-fai`},{pl: `Czy macie Wi-Fi?`, de: `Haben Sie WLAN?`, ipa: `tschi ma-tsche wai-fai`},{pl: `Potrzebuję ładowarki.`, de: `Ich brauche ein Ladegerät.`, ipa: `po-tsche-bu-je wa-do-var-ki`},{pl: `Gdzie jest gniazdko?`, de: `Wo ist eine Steckdose?`, ipa: `gdschje jest gnjast-ko`},{pl: `Mój telefon nie działa.`, de: `Mein Telefon funktioniert nicht.`, ipa: `muj te-le-fon nje dschja-wa`},{pl: `Proszę wpisać adres.`, de: `Bitte geben Sie die Adresse ein.`, ipa: `pro-sche fpi-satsch a-dres`}], grammar: `„Do“ kann auch „für/zu“ bedeuten, wie in „hasło do Wi-Fi“. „Mój“ bedeutet „mein“ für maskuline Wörter wie „telefon“. Bei technischen Problemen ist „nie działa“ sehr praktisch: „es funktioniert nicht“.`, practice: [`Frage nach dem WLAN-Passwort.`,`Frage nach einer Steckdose.`,`Sage, dass dein Telefon nicht funktioniert.`,`Bitte um ein Ladegerät.`,`Bitte jemanden, eine Adresse einzugeben.`]},{day: 21, title: `Menschen treffen und Small Talk`, title_native: `Poznawanie ludzi i rozmowa towarzyska`, focus: `In einem Café in Krakau kommst du mit Einheimischen ins Gespräch. Heute lernst du einfache Small-Talk-Fragen und freundliche Antworten.`, vocab: [{pl: `skąd`, de: `woher`, ipa: `skont`},{pl: `tutaj`, de: `hier`, ipa: `tu-tai`},{pl: `tam`, de: `dort`, ipa: `tam`},{pl: `praca`, de: `Arbeit`, ipa: `pra-tsa`},{pl: `wakacje`, de: `Urlaub`, ipa: `wa-ka-tsje`},{pl: `podróż`, de: `Reise`, ipa: `po-drusch`},{pl: `ładny`, de: `schön`, ipa: `wad-ni`},{pl: `ciekawy`, de: `interessant`, ipa: `tsche-ka-wi`},{pl: `miasto`, de: `Stadt`, ipa: `mjas-to`},{pl: `ludzie`, de: `Leute`, ipa: `lu-dsche`}], phrases: [{pl: `Skąd jesteś?`, de: `Woher kommst du?`, ipa: `skont jes-tesch`},{pl: `Jestem tutaj na wakacjach.`, de: `Ich bin hier im Urlaub.`, ipa: `jes-tem tu-tai na wa-ka-tsjach`},{pl: `To miasto jest piękne.`, de: `Diese Stadt ist schön.`, ipa: `to mjas-to jest pjenk-ne`},{pl: `Podoba mi się Polska.`, de: `Polen gefällt mir.`, ipa: `po-do-ba mi schje pol-ska`},{pl: `Czym się zajmujesz?`, de: `Was machst du beruflich?`, ipa: `tschim schje sai-mu-jesch`},{pl: `Miło było cię poznać.`, de: `Es war schön, dich kennenzulernen.`, ipa: `mi-wo bi-wo tsche pos-natsch`}], grammar: `„Podoba mi się...” bedeutet „... gefällt mir“ und ist im Polnischen anders gebaut als im Deutschen. „Polska“ ist Polen, „Polska mi się podoba“ oder „Podoba mi się Polska“ sind beide verständlich. Im informellen Gespräch benutzt du „jesteś“ für „du bist“.`, practice: [`Sage, dass du in Polen im Urlaub bist.`,`Frage jemanden, woher er oder sie kommt.`,`Sage, dass dir Polen gefällt.`,`Mache ein Kompliment über eine Stadt.`,`Beende ein Gespräch freundlich.`]},{day: 22, title: `Einladungen und Verabredungen`, title_native: `Zaproszenia i spotkania`, focus: `In Poznań willst du dich mit neuen Bekannten treffen. Heute lernst du, Pläne zu machen, Zeiten vorzuschlagen und höflich abzusagen.`, vocab: [{pl: `spotkanie`, de: `Treffen`, ipa: `spot-ka-nje`},{pl: `kawiarnia`, de: `Café`, ipa: `ka-vjar-nja`},{pl: `restauracja`, de: `Restaurant`, ipa: `res-tau-ra-tsja`},{pl: `kino`, de: `Kino`, ipa: `ki-no`},{pl: `park`, de: `Park`, ipa: `park`},{pl: `wieczór`, de: `Abend`, ipa: `wje-tschur`},{pl: `może`, de: `vielleicht/kann`, ipa: `mo-sche`},{pl: `chcę`, de: `ich möchte`, ipa: `chtse`},{pl: `mogę`, de: `ich kann`, ipa: `mo-ge`},{pl: `niestety`, de: `leider`, ipa: `nje-ste-ti`}], phrases: [{pl: `Chcesz iść na kawę?`, de: `Möchtest du einen Kaffee trinken gehen?`, ipa: `ch-tschesch ischtsch na ka-we`},{pl: `Może jutro?`, de: `Vielleicht morgen?`, ipa: `mo-sche ju-tro`},{pl: `Dzisiaj nie mogę.`, de: `Heute kann ich nicht.`, ipa: `dschi-schaj nje mo-ge`},{pl: `Spotkajmy się o szóstej.`, de: `Treffen wir uns um sechs.`, ipa: `spot-kai-mi schje o schus-tej`},{pl: `Gdzie się spotkamy?`, de: `Wo treffen wir uns?`, ipa: `gdschje schje spot-ka-mi`},{pl: `Niestety, mam inne plany.`, de: `Leider habe ich andere Pläne.`, ipa: `nje-ste-ti mam in-ne pla-ni`}], grammar: `„Chcesz...?“ heißt „möchtest du/willst du...?“. „Spotkajmy się“ ist eine natürliche Einladung: „Lass uns uns treffen“. Für Absagen klingt „niestety“ höflich und weich.`, practice: [`Lade jemanden auf einen Kaffee ein.`,`Schlage morgen als Termin vor.`,`Sage höflich, dass du heute nicht kannst.`,`Vereinbare ein Treffen um sechs.`,`Frage, wo ihr euch trefft.`]},{day: 23, title: `Familie und persönliche Informationen`, title_native: `Rodzina i informacje osobiste`, focus: `In einem Hostel in Warschau erzählst du ein bisschen über dich. Heute lernst du Familie, Wohnort und einfache persönliche Details.`, vocab: [{pl: `rodzina`, de: `Familie`, ipa: `ro-dschi-na`},{pl: `mama`, de: `Mutter`, ipa: `ma-ma`},{pl: `tata`, de: `Vater`, ipa: `ta-ta`},{pl: `brat`, de: `Bruder`, ipa: `brat`},{pl: `siostra`, de: `Schwester`, ipa: `schos-tra`},{pl: `dziecko`, de: `Kind`, ipa: `dschets-ko`},{pl: `dom`, de: `Zuhause/Haus`, ipa: `dom`},{pl: `mieszkanie`, de: `Wohnung`, ipa: `mjesch-ka-nje`},{pl: `mieszkam`, de: `ich wohne`, ipa: `mjesch-kam`},{pl: `pracuję`, de: `ich arbeite`, ipa: `pra-tsu-je`}], phrases: [{pl: `Mieszkam w Berlinie.`, de: `Ich wohne in Berlin.`, ipa: `mjesch-kam w ber-li-nje`},{pl: `Mam brata.`, de: `Ich habe einen Bruder.`, ipa: `mam bra-ta`},{pl: `Mam siostrę.`, de: `Ich habe eine Schwester.`, ipa: `mam schos-tre`},{pl: `Moja rodzina jest w Niemczech.`, de: `Meine Familie ist in Deutschland.`, ipa: `mo-ja ro-dschi-na jest w njem-tschech`},{pl: `Pracuję w hotelu.`, de: `Ich arbeite in einem Hotel.`, ipa: `pra-tsu-je w ho-te-lu`},{pl: `A ty?`, de: `Und du?`, ipa: `a ti`}], grammar: `„Mieszkam w...” bedeutet „ich wohne in...“. „Mam“ kann Besitz und Beziehungen ausdrücken: „mam brata“, „mam siostrę“. „A ty?“ ist eine einfache informelle Rückfrage und hält ein Gespräch am Laufen.`, practice: [`Sage, wo du wohnst.`,`Sage, dass du einen Bruder oder eine Schwester hast.`,`Sage, wo deine Familie ist.`,`Sage, wo du arbeitest.`,`Stelle am Ende die Rückfrage „A ty?“.`]},{day: 24, title: `Post, Souvenirs und Geschenke`, title_native: `Poczta, pamiątki i prezenty`, focus: `In Danzig kaufst du Souvenirs und möchtest eine Postkarte verschicken. Heute lernst du Wörter für Geschenke, Post und einfache Versandfragen.`, vocab: [{pl: `pamiątka`, de: `Souvenir`, ipa: `pa-mjont-ka`},{pl: `prezent`, de: `Geschenk`, ipa: `pre-sent`},{pl: `pocztówka`, de: `Postkarte`, ipa: `potsch-tuf-ka`},{pl: `znaczek`, de: `Briefmarke`, ipa: `sna-tschek`},{pl: `poczta`, de: `Post`, ipa: `potsch-ta`},{pl: `adres`, de: `Adresse`, ipa: `a-dres`},{pl: `koperta`, de: `Umschlag`, ipa: `ko-per-ta`},{pl: `wysłać`, de: `schicken`, ipa: `wi-swatsch`},{pl: `drogi`, de: `teuer`, ipa: `dro-gi`},{pl: `tani`, de: `billig`, ipa: `ta-ni`}], phrases: [{pl: `Poproszę pocztówkę.`, de: `Eine Postkarte bitte.`, ipa: `po-pro-sche potsch-tuf-ke`},{pl: `Gdzie mogę kupić znaczek?`, de: `Wo kann ich eine Briefmarke kaufen?`, ipa: `gdschje mo-ge ku-pitsch sna-tschek`},{pl: `Chcę wysłać kartkę do Niemiec.`, de: `Ich möchte eine Karte nach Deutschland schicken.`, ipa: `chtse wi-swatsch kart-ke do njem-jets`},{pl: `To jest prezent.`, de: `Das ist ein Geschenk.`, ipa: `to jest pre-sent`},{pl: `Czy macie coś tańszego?`, de: `Haben Sie etwas Günstigeres?`, ipa: `tschi ma-tsche tschosh tanj-sche-go`},{pl: `To piękna pamiątka.`, de: `Das ist ein schönes Souvenir.`, ipa: `to pjenk-na pa-mjont-ka`}], grammar: `„Chcę“ bedeutet „ich möchte/ich will“ und ist direkt, aber im Alltag normal. Für höflichere Käufe bleibt „poproszę“ besser. „Do Niemiec“ bedeutet „nach Deutschland“ und passt für Versand oder Reisen.`, practice: [`Kaufe eine Postkarte.`,`Frage nach einer Briefmarke.`,`Sage, dass du eine Karte nach Deutschland schicken möchtest.`,`Frage nach etwas Günstigerem.`,`Sage, dass etwas ein Geschenk ist.`]},{day: 25, title: `Bank, Geldautomat und Bezahlen`, title_native: `Bank, bankomat i płatności`, focus: `In Łódź brauchst du Bargeld und willst sicher bezahlen. Heute lernst du Bankwörter, Geldautomat und Zahlungsprobleme.`, vocab: [{pl: `bank`, de: `Bank`, ipa: `bank`},{pl: `bankomat`, de: `Geldautomat`, ipa: `ban-ko-mat`},{pl: `gotówka`, de: `Bargeld`, ipa: `go-tuf-ka`},{pl: `karta`, de: `Karte`, ipa: `kar-ta`},{pl: `płatność`, de: `Zahlung`, ipa: `pwaat-noschtsch`},{pl: `PIN`, de: `PIN`, ipa: `pin`},{pl: `konto`, de: `Konto`, ipa: `kon-to`},{pl: `opłata`, de: `Gebühr`, ipa: `o-pwa-ta`},{pl: `problem`, de: `Problem`, ipa: `pro-blem`},{pl: `działa`, de: `funktioniert`, ipa: `dschja-wa`}], phrases: [{pl: `Gdzie jest bankomat?`, de: `Wo ist ein Geldautomat?`, ipa: `gdschje jest ban-ko-mat`},{pl: `Czy mogę zapłacić kartą?`, de: `Kann ich mit Karte bezahlen?`, ipa: `tschi mo-ge sa-pwa-tschitsch kar-tom`},{pl: `Czy przyjmujecie gotówkę?`, de: `Nehmen Sie Bargeld an?`, ipa: `tschi pschi-mu-je-tsche go-tuf-ke`},{pl: `Moja karta nie działa.`, de: `Meine Karte funktioniert nicht.`, ipa: `mo-ja kar-ta nje dschja-wa`},{pl: `Czy jest opłata?`, de: `Gibt es eine Gebühr?`, ipa: `tschi jest o-pwa-ta`},{pl: `Potrzebuję gotówki.`, de: `Ich brauche Bargeld.`, ipa: `po-tsche-bu-je go-tuf-ki`}], grammar: `„Karta“ ist weiblich, daher „moja karta“ für „meine Karte“. „Nie działa“ kannst du für Karten, Telefone, WLAN oder Automaten verwenden. Bei Gebühren reicht die kurze Frage „Czy jest opłata?“.`, practice: [`Frage nach einem Geldautomaten.`,`Frage, ob du mit Karte bezahlen kannst.`,`Sage, dass deine Karte nicht funktioniert.`,`Frage nach einer Gebühr.`,`Sage, dass du Bargeld brauchst.`]},{day: 26, title: `Unterkunftsprobleme lösen`, title_native: `Rozwiązywanie problemów z noclegiem`, focus: `In einem Apartment in Krakau funktioniert etwas nicht. Heute lernst du, Probleme höflich zu melden und Lösungen zu erbitten.`, vocab: [{pl: `problem`, de: `Problem`, ipa: `pro-blem`},{pl: `pokój`, de: `Zimmer`, ipa: `po-kuj`},{pl: `drzwi`, de: `Tür`, ipa: `dschwi`},{pl: `okno`, de: `Fenster`, ipa: `ok-no`},{pl: `klimatyzacja`, de: `Klimaanlage`, ipa: `kli-ma-ti-sa-tsja`},{pl: `ogrzewanie`, de: `Heizung`, ipa: `o-gsche-wa-nje`},{pl: `prysznic`, de: `Dusche`, ipa: `pri-sch-nits`},{pl: `ręcznik`, de: `Handtuch`, ipa: `rent-sch-nik`},{pl: `hałas`, de: `Lärm`, ipa: `ha-was`},{pl: `czysto`, de: `sauber`, ipa: `tschis-to`}], phrases: [{pl: `Mam problem z pokojem.`, de: `Ich habe ein Problem mit dem Zimmer.`, ipa: `mam pro-blem s po-ko-jem`},{pl: `Klimatyzacja nie działa.`, de: `Die Klimaanlage funktioniert nicht.`, ipa: `kli-ma-ti-sa-tsja nje dschja-wa`},{pl: `Prysznic jest zepsuty.`, de: `Die Dusche ist kaputt.`, ipa: `pri-sch-nits jest se-psu-ti`},{pl: `Potrzebuję ręcznika.`, de: `Ich brauche ein Handtuch.`, ipa: `po-tsche-bu-je rent-sch-ni-ka`},{pl: `W pokoju jest hałas.`, de: `Im Zimmer ist Lärm.`, ipa: `w po-ko-ju jest ha-was`},{pl: `Czy można zmienić pokój?`, de: `Kann man das Zimmer wechseln?`, ipa: `tschi mosch-na smje-nitsch po-kuj`}], grammar: `„Mam problem z...” bedeutet „ich habe ein Problem mit...“ und braucht danach oft eine angepasste Form, aber die feste Struktur hilft sofort. „Zepsuty“ heißt kaputt. „Czy można...?“ ist höflich, wenn du um eine Lösung bittest.`, practice: [`Melde ein Problem mit dem Zimmer.`,`Sage, dass die Klimaanlage nicht funktioniert.`,`Bitte um ein Handtuch.`,`Sage, dass es im Zimmer laut ist.`,`Frage, ob man das Zimmer wechseln kann.`]},{day: 27, title: `Kultur, Höflichkeit und Einladungen`, title_native: `Kultura, uprzejmość i zaproszenia`, focus: `In Polen bist du bei Einheimischen zu Besuch oder lernst neue Leute kennen. Heute lernst du höfliche Reaktionen, Komplimente und kleine soziale Sätze.`, vocab: [{pl: `dziękuję`, de: `danke`, ipa: `dschjen-ku-je`},{pl: `proszę`, de: `bitte`, ipa: `pro-sche`},{pl: `smaczne`, de: `lecker`, ipa: `smatsch-ne`},{pl: `piękne`, de: `schön`, ipa: `pjenk-ne`},{pl: `gość`, de: `Gast`, ipa: `goschtsch`},{pl: `dom`, de: `Haus/Zuhause`, ipa: `dom`},{pl: `zaproszenie`, de: `Einladung`, ipa: `sa-pro-sche-nje`},{pl: `miły`, de: `nett`, ipa: `mi-wi`},{pl: `uprzejmy`, de: `höflich`, ipa: `u-pschei-mi`},{pl: `prezent`, de: `Geschenk`, ipa: `pre-sent`}], phrases: [{pl: `Dziękuję za zaproszenie.`, de: `Danke für die Einladung.`, ipa: `dschjen-ku-je sa sa-pro-sche-nje`},{pl: `To jest bardzo smaczne.`, de: `Das ist sehr lecker.`, ipa: `to jest bar-dso smatsch-ne`},{pl: `Masz piękny dom.`, de: `Du hast ein schönes Zuhause.`, ipa: `masch pjenk-ni dom`},{pl: `Bardzo mi miło.`, de: `Es freut mich sehr.`, ipa: `bar-dso mi mi-wo`},{pl: `To dla ciebie.`, de: `Das ist für dich.`, ipa: `to dla tsche-bje`},{pl: `Dziękuję za wszystko.`, de: `Danke für alles.`, ipa: `dschjen-ku-je sa fschist-ko`}], grammar: `„Za“ bedeutet hier „für“: „dziękuję za zaproszenie“. Komplimente sind in Polen willkommen, besonders wenn sie schlicht und ehrlich klingen. „To dla ciebie“ ist ein guter Satz, wenn du ein kleines Geschenk überreichst.`, practice: [`Bedanke dich für eine Einladung.`,`Sage, dass das Essen sehr lecker ist.`,`Mache ein Kompliment über das Zuhause.`,`Überreiche ein kleines Geschenk.`,`Bedanke dich am Ende für alles.`]},{day: 28, title: `Pläne ändern und Probleme erklären`, title_native: `Zmiana planów i wyjaśnianie problemów`, focus: `Auf Reisen ändern sich Zeiten, Züge und Treffen. Heute lernst du, Verspätungen, Änderungen und Entschuldigungen zu formulieren.`, vocab: [{pl: `spóźnienie`, de: `Verspätung`, ipa: `spujsch-nje-nje`},{pl: `zmiana`, de: `Änderung`, ipa: `smja-na`},{pl: `plan`, de: `Plan`, ipa: `plan`},{pl: `później`, de: `später`, ipa: `pusch-njej`},{pl: `wcześniej`, de: `früher`, ipa: `ftschesch-njej`},{pl: `teraz`, de: `jetzt`, ipa: `te-ras`},{pl: `zaraz`, de: `gleich`, ipa: `sa-ras`},{pl: `czekam`, de: `ich warte`, ipa: `tsche-kam`},{pl: `przepraszam`, de: `Entschuldigung`, ipa: `psche-pra-scham`},{pl: `odwołany`, de: `abgesagt`, ipa: `od-wo-wa-ni`}], phrases: [{pl: `Przepraszam za spóźnienie.`, de: `Entschuldigung für die Verspätung.`, ipa: `psche-pra-scham sa spujsch-nje-nje`},{pl: `Mój pociąg jest opóźniony.`, de: `Mein Zug hat Verspätung.`, ipa: `muj po-tschong jest o-pusch-njo-ni`},{pl: `Czy możemy spotkać się później?`, de: `Können wir uns später treffen?`, ipa: `tschi mo-sche-mi spot-katsch schje pusch-njej`},{pl: `Muszę zmienić plan.`, de: `Ich muss den Plan ändern.`, ipa: `mu-sche smje-nitsch plan`},{pl: `Czekam przed hotelem.`, de: `Ich warte vor dem Hotel.`, ipa: `tsche-kam pschet ho-te-lem`},{pl: `To jest odwołane.`, de: `Das ist abgesagt.`, ipa: `to jest od-wo-wa-ne`}], grammar: `„Muszę“ bedeutet „ich muss“ und ist in Reiseproblemen sehr hilfreich. „Możemy“ bedeutet „wir können“ und macht Vorschläge höflich. „Przed hotelem“ heißt „vor dem Hotel“ und ist ein nützlicher Treffpunkt-Ausdruck.`, practice: [`Entschuldige dich für eine Verspätung.`,`Sage, dass dein Zug verspätet ist.`,`Bitte um ein späteres Treffen.`,`Sage, dass du den Plan ändern musst.`,`Sage, wo du wartest.`]},{day: 29, title: `Meinungen und Empfehlungen`, title_native: `Opinie i rekomendacje`, focus: `In Krakau fragst du nach Empfehlungen und sagst, was dir gefällt. Heute lernst du Meinungen über Essen, Orte und Aktivitäten.`, vocab: [{pl: `opinia`, de: `Meinung`, ipa: `o-pi-nja`},{pl: `polecenie`, de: `Empfehlung`, ipa: `po-le-tse-nje`},{pl: `dobry`, de: `gut`, ipa: `dob-ri`},{pl: `zły`, de: `schlecht`, ipa: `zwi`},{pl: `piękny`, de: `schön`, ipa: `pjenk-ni`},{pl: `nudny`, de: `langweilig`, ipa: `nud-ni`},{pl: `ciekawy`, de: `interessant`, ipa: `tsche-ka-wi`},{pl: `najlepszy`, de: `der beste`, ipa: `naj-lep-schi`},{pl: `ulubiony`, de: `Lieblings-`, ipa: `u-lu-bjo-ni`},{pl: `warto`, de: `es lohnt sich`, ipa: `var-to`}], phrases: [{pl: `Co polecasz?`, de: `Was empfiehlst du?`, ipa: `tso po-le-tsasch`},{pl: `Czy warto tam iść?`, de: `Lohnt es sich, dorthin zu gehen?`, ipa: `tschi var-to tam ischtsch`},{pl: `To jest moje ulubione miejsce.`, de: `Das ist mein Lieblingsort.`, ipa: `to jest mo-je u-lu-bjo-ne mjej-stse`},{pl: `Jedzenie jest bardzo dobre.`, de: `Das Essen ist sehr gut.`, ipa: `je-dse-nje jest bar-dso dob-re`},{pl: `Nie podoba mi się to.`, de: `Das gefällt mir nicht.`, ipa: `nje po-do-ba mi schje to`},{pl: `To było ciekawe.`, de: `Das war interessant.`, ipa: `to bi-wo tsche-ka-ve`}], grammar: `„Warto“ ist ein kleines, starkes Wort: „Czy warto?“ bedeutet „Lohnt es sich?“. „Podoba mi się“ für Gefallen und „nie podoba mi się“ für Nichtgefallen sind sehr natürliche Ausdrücke. Empfehlungen im informellen Gespräch fragst du mit „Co polecasz?“.`, practice: [`Frage nach einer Empfehlung.`,`Frage, ob sich ein Ort lohnt.`,`Sage, dass ein Ort dein Lieblingsort ist.`,`Sage, dass das Essen sehr gut ist.`,`Sage höflich, dass dir etwas nicht gefällt.`]},{day: 30, title: `Reisetag: alles kombinieren`, title_native: `Dzień podróży: łączenie wszystkiego`, focus: `Am letzten Tag reist du von Warschau zurück und nutzt Hotel-, Taxi-, Flughafen- und Höflichkeitssprache zusammen. Heute wiederholst du die wichtigsten Reisehandlungen in einem Ablauf.`, vocab: [{pl: `walizka`, de: `Koffer`, ipa: `wa-lisch-ka`},{pl: `bagaż`, de: `Gepäck`, ipa: `ba-gasch`},{pl: `lot`, de: `Flug`, ipa: `lot`},{pl: `bramka`, de: `Gate`, ipa: `bram-ka`},{pl: `odprawa`, de: `Check-in`, ipa: `od-pra-wa`},{pl: `paszport`, de: `Reisepass`, ipa: `pasch-port`},{pl: `kontrola`, de: `Kontrolle`, ipa: `kon-tro-la`},{pl: `opóźnienie`, de: `Verspätung`, ipa: `o-pusch-nje-nje`},{pl: `wyjazd`, de: `Abreise`, ipa: `wi-jasd`},{pl: `powrót`, de: `Rückkehr`, ipa: `pov-rut`}], phrases: [{pl: `Muszę jechać na lotnisko.`, de: `Ich muss zum Flughafen fahren.`, ipa: `mu-sche je-chatsch na lot-nis-ko`},{pl: `Gdzie jest odprawa?`, de: `Wo ist der Check-in?`, ipa: `gdschje jest od-pra-wa`},{pl: `Mam tylko jeden bagaż.`, de: `Ich habe nur ein Gepäckstück.`, ipa: `mam til-ko je-den ba-gasch`},{pl: `Czy lot jest opóźniony?`, de: `Hat der Flug Verspätung?`, ipa: `tschi lot jest o-pusch-njo-ni`},{pl: `Gdzie jest bramka numer pięć?`, de: `Wo ist Gate Nummer fünf?`, ipa: `gdschje jest bram-ka nu-mer pjen-tsch`},{pl: `Dziękuję za pomoc.`, de: `Danke für die Hilfe.`, ipa: `dschjen-ku-je sa po-mots`}], grammar: `Am Reisetag kombinierst du viele Strukturen: „muszę“ für Notwendigkeit, „gdzie jest“ für Orte und „czy“ für Ja/Nein-Fragen. Kurze, klare Sätze funktionieren am besten, besonders am Flughafen. Wiederhole feste Reiseblöcke, statt jedes Wort einzeln neu zu bauen.`, practice: [`Sage, dass du zum Flughafen musst.`,`Frage nach dem Check-in.`,`Sage, dass du nur ein Gepäckstück hast.`,`Frage, ob der Flug verspätet ist.`,`Bedanke dich für Hilfe und verabschiede dich höflich.`]}];

var CONVERSATIONS_DE_PL = [{id: 1, title: `Kaffee in Krakau bestellen`, scene: `Du bist in einer kleinen Kawiarnia in der Altstadt von Krakau. Es ist Vormittag, und du möchtest Kaffee, Kuchen und einen freien Tisch finden.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, de: `Guten Tag, was darf ich bringen?`},{who: `you`, pl: `Dzień dobry, poproszę kawę.`, de: `Guten Tag, einen Kaffee bitte.`},{who: `them`, pl: `Z mlekiem czy bez mleka?`, de: `Mit Milch oder ohne Milch?`},{who: `you`, pl: `Z mlekiem, ale bez cukru, proszę.`, de: `Mit Milch, aber ohne Zucker bitte.`},{who: `them`, pl: `Czy coś jeszcze?`, de: `Noch etwas?`},{who: `you`, pl: `Tak, poproszę ciasto.`, de: `Ja, Kuchen bitte.`},{who: `them`, pl: `Mamy sernik i szarlotkę.`, de: `Wir haben Käsekuchen und Apfelkuchen.`},{who: `you`, pl: `Poproszę sernik.`, de: `Käsekuchen bitte.`},{who: `them`, pl: `Czy tutaj czy na wynos?`, de: `Hier oder zum Mitnehmen?`},{who: `you`, pl: `Tutaj. Czy jest wolny stolik?`, de: `Hier. Ist ein Tisch frei?`},{who: `them`, pl: `Tak, przy oknie.`, de: `Ja, am Fenster.`},{who: `you`, pl: `Dziękuję bardzo.`, de: `Vielen Dank.`}]},{id: 2, title: `Einchecken im Hotel in Warschau`, scene: `Du kommst abends in einem Hotel in Warschau an. Du hast eine Reservierung und möchtest wissen, ob Frühstück im Preis enthalten ist.`, lines: [{who: `them`, pl: `Dobry wieczór, witamy w hotelu.`, de: `Guten Abend, willkommen im Hotel.`},{who: `you`, pl: `Dobry wieczór, mam rezerwację.`, de: `Guten Abend, ich habe eine Reservierung.`},{who: `them`, pl: `Na jakie nazwisko?`, de: `Auf welchen Namen?`},{who: `you`, pl: `Na nazwisko Müller.`, de: `Auf den Namen Müller.`},{who: `them`, pl: `Poproszę paszport.`, de: `Den Reisepass bitte.`},{who: `you`, pl: `Proszę. Czy śniadanie jest w cenie?`, de: `Bitte. Ist Frühstück im Preis inbegriffen?`},{who: `them`, pl: `Tak, śniadanie jest od siódmej do dziesiątej.`, de: `Ja, Frühstück ist von sieben bis zehn.`},{who: `you`, pl: `Dziękuję. Gdzie jest winda?`, de: `Danke. Wo ist der Aufzug?`},{who: `them`, pl: `Winda jest po prawej stronie.`, de: `Der Aufzug ist auf der rechten Seite.`},{who: `you`, pl: `Które piętro?`, de: `Welches Stockwerk?`},{who: `them`, pl: `Drugie piętro, pokój numer dwadzieścia jeden.`, de: `Zweiter Stock, Zimmer Nummer einundzwanzig.`},{who: `you`, pl: `Dziękuję, do widzenia.`, de: `Danke, auf Wiedersehen.`}]},{id: 3, title: `Nach dem Weg zum Marktplatz fragen`, scene: `Du bist in Breslau und suchst den Rynek. Du hältst eine Person auf der Straße höflich an und bittest um eine einfache Wegbeschreibung.`, lines: [{who: `you`, pl: `Przepraszam, gdzie jest rynek?`, de: `Entschuldigung, wo ist der Marktplatz?`},{who: `them`, pl: `Rynek jest blisko.`, de: `Der Marktplatz ist nah.`},{who: `you`, pl: `Czy mogę iść pieszo?`, de: `Kann ich zu Fuß gehen?`},{who: `them`, pl: `Tak, proszę iść prosto do świateł.`, de: `Ja, gehen Sie geradeaus bis zur Ampel.`},{who: `you`, pl: `Potem w prawo czy w lewo?`, de: `Dann rechts oder links?`},{who: `them`, pl: `Proszę skręcić w lewo.`, de: `Biegen Sie bitte links ab.`},{who: `you`, pl: `Czy rynek jest za kościołem?`, de: `Ist der Marktplatz hinter der Kirche?`},{who: `them`, pl: `Tak, dokładnie.`, de: `Ja, genau.`},{who: `you`, pl: `Ile minut pieszo?`, de: `Wie viele Minuten zu Fuß?`},{who: `them`, pl: `Około pięciu minut.`, de: `Ungefähr fünf Minuten.`},{who: `you`, pl: `Dziękuję za pomoc.`, de: `Danke für die Hilfe.`},{who: `them`, pl: `Nie ma problemu.`, de: `Kein Problem.`}]},{id: 4, title: `Abendessen im Restaurant in Danzig`, scene: `Du sitzt in einem Restaurant in Danzig und möchtest ein typisches polnisches Gericht probieren. Du fragst nach Empfehlungen und prüfst, ob das Gericht Fleisch enthält.`, lines: [{who: `them`, pl: `Dzień dobry, czy podać menu?`, de: `Guten Tag, soll ich die Speisekarte bringen?`},{who: `you`, pl: `Tak, poproszę menu.`, de: `Ja, die Karte bitte.`},{who: `them`, pl: `Proszę bardzo.`, de: `Sehr gern.`},{who: `you`, pl: `Co pani poleca?`, de: `Was empfehlen Sie?`},{who: `them`, pl: `Polecam pierogi i zupę pomidorową.`, de: `Ich empfehle Pierogi und Tomatensuppe.`},{who: `you`, pl: `Czy pierogi są z mięsem?`, de: `Sind die Pierogi mit Fleisch?`},{who: `them`, pl: `Mamy z mięsem i wegetariańskie.`, de: `Wir haben welche mit Fleisch und vegetarische.`},{who: `you`, pl: `Poproszę pierogi wegetariańskie.`, de: `Vegetarische Pierogi bitte.`},{who: `them`, pl: `Do picia?`, de: `Zum Trinken?`},{who: `you`, pl: `Poproszę wodę gazowaną.`, de: `Sprudelwasser bitte.`},{who: `them`, pl: `Oczywiście.`, de: `Natürlich.`},{who: `you`, pl: `Dziękuję bardzo.`, de: `Vielen Dank.`}]},{id: 5, title: `Straßenbahnticket in Poznań kaufen`, scene: `Du bist an einem Automaten oder Schalter in Poznań und brauchst ein Ticket für die Straßenbahn. Du möchtest mit Karte bezahlen und den richtigen Bahnsteig finden.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, de: `Guten Tag, wobei kann ich helfen?`},{who: `you`, pl: `Dzień dobry, poproszę jeden bilet na tramwaj.`, de: `Guten Tag, ein Straßenbahnticket bitte.`},{who: `them`, pl: `Normalny czy ulgowy?`, de: `Normal oder ermäßigt?`},{who: `you`, pl: `Normalny, proszę.`, de: `Normal bitte.`},{who: `them`, pl: `To kosztuje sześć złotych.`, de: `Das kostet sechs Złoty.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, de: `Kann ich mit Karte bezahlen?`},{who: `them`, pl: `Tak, proszę przyłożyć kartę.`, de: `Ja, halten Sie bitte die Karte hin.`},{who: `you`, pl: `Dziękuję. Gdzie jest przystanek?`, de: `Danke. Wo ist die Haltestelle?`},{who: `them`, pl: `Przystanek jest obok dworca.`, de: `Die Haltestelle ist neben dem Bahnhof.`},{who: `you`, pl: `Czy to jest daleko?`, de: `Ist das weit?`},{who: `them`, pl: `Nie, dwie minuty pieszo.`, de: `Nein, zwei Minuten zu Fuß.`},{who: `you`, pl: `Świetnie, dziękuję.`, de: `Super, danke.`}]},{id: 6, title: `Einkaufen und nach Größen fragen`, scene: `Du bist in einem Kleidungsgeschäft in Katowice. Du suchst eine schwarze Jacke, möchtest eine andere Größe und fragst nach der Umkleidekabine.`, lines: [{who: `them`, pl: `Dzień dobry, czy mogę pomóc?`, de: `Guten Tag, kann ich helfen?`},{who: `you`, pl: `Dzień dobry, szukam czarnej kurtki.`, de: `Guten Tag, ich suche eine schwarze Jacke.`},{who: `them`, pl: `Jaki rozmiar?`, de: `Welche Größe?`},{who: `you`, pl: `Średni rozmiar, proszę.`, de: `Mittlere Größe bitte.`},{who: `them`, pl: `Proszę, ta kurtka jest czarna.`, de: `Bitte, diese Jacke ist schwarz.`},{who: `you`, pl: `Czy macie większy rozmiar?`, de: `Haben Sie eine größere Größe?`},{who: `them`, pl: `Tak, zaraz przyniosę.`, de: `Ja, ich bringe sie gleich.`},{who: `you`, pl: `Gdzie jest przymierzalnia?`, de: `Wo ist die Umkleidekabine?`},{who: `them`, pl: `Po lewej stronie.`, de: `Auf der linken Seite.`},{who: `you`, pl: `Dziękuję. To mi pasuje.`, de: `Danke. Das passt mir.`},{who: `them`, pl: `Czy płaci pan kartą?`, de: `Zahlen Sie mit Karte?`},{who: `you`, pl: `Tak, kartą.`, de: `Ja, mit Karte.`}]},{id: 7, title: `Hilfe in der Apotheke`, scene: `Du bist in Zakopane und hast Kopfschmerzen. In der Apotheke erklärst du dein Problem und fragst, ob du ein Rezept brauchst.`, lines: [{who: `them`, pl: `Dzień dobry, słucham.`, de: `Guten Tag, ich höre.`},{who: `you`, pl: `Dzień dobry, boli mnie głowa.`, de: `Guten Tag, mein Kopf tut weh.`},{who: `them`, pl: `Czy ma pan gorączkę?`, de: `Haben Sie Fieber?`},{who: `you`, pl: `Nie, nie mam gorączki.`, de: `Nein, ich habe kein Fieber.`},{who: `them`, pl: `Potrzebuje pan tabletek przeciwbólowych.`, de: `Sie brauchen Schmerztabletten.`},{who: `you`, pl: `Czy potrzebuję recepty?`, de: `Brauche ich ein Rezept?`},{who: `them`, pl: `Nie, bez recepty.`, de: `Nein, ohne Rezept.`},{who: `you`, pl: `Poproszę jedno opakowanie.`, de: `Eine Packung bitte.`},{who: `them`, pl: `Proszę pić dużo wody.`, de: `Bitte trinken Sie viel Wasser.`},{who: `you`, pl: `Dobrze, dziękuję.`, de: `Gut, danke.`},{who: `them`, pl: `To kosztuje dwanaście złotych.`, de: `Das kostet zwölf Złoty.`},{who: `you`, pl: `Proszę, płacę kartą.`, de: `Bitte, ich zahle mit Karte.`}]},{id: 8, title: `Small Talk mit einer lokalen Person`, scene: `Du sitzt in einem Park in Krakau und kommst mit einer freundlichen Person ins Gespräch. Ihr sprecht über Herkunft, Reise und Eindrücke von Polen.`, lines: [{who: `you`, pl: `Cześć, czy to miejsce jest wolne?`, de: `Hallo, ist dieser Platz frei?`},{who: `them`, pl: `Tak, proszę.`, de: `Ja, bitte.`},{who: `you`, pl: `Dziękuję. Jestem tutaj na wakacjach.`, de: `Danke. Ich bin hier im Urlaub.`},{who: `them`, pl: `Skąd jesteś?`, de: `Woher kommst du?`},{who: `you`, pl: `Jestem z Niemiec.`, de: `Ich bin aus Deutschland.`},{who: `them`, pl: `Jak podoba ci się Kraków?`, de: `Wie gefällt dir Krakau?`},{who: `you`, pl: `Bardzo mi się podoba. To piękne miasto.`, de: `Es gefällt mir sehr. Das ist eine schöne Stadt.`},{who: `them`, pl: `Byłeś już na rynku?`, de: `Warst du schon auf dem Marktplatz?`},{who: `you`, pl: `Tak, rynek jest bardzo ciekawy.`, de: `Ja, der Marktplatz ist sehr interessant.`},{who: `them`, pl: `Co jeszcze chcesz zobaczyć?`, de: `Was möchtest du noch sehen?`},{who: `you`, pl: `Chcę zobaczyć zamek i muzeum.`, de: `Ich möchte das Schloss und das Museum sehen.`},{who: `them`, pl: `Miłego dnia!`, de: `Einen schönen Tag!`}]}];